package com.example.networking

import okhttp3.CertificatePinner

object CertificatePinnerConfig {

    // Production certificate pins (SHA-256 hashes of the Subject Public Key Info)
    // You must replace these with actual pin values obtained from your server certificates.
    // Include at least one backup pin for key rotation.
    private val PRODUCTION_PINS = arrayOf(
        "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=",  // Primary pin
        "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB="   // Backup pin
    )

    private val STAGING_PINS = arrayOf(
        "sha256/CCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCC=",
        "sha256/DDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDD="
    )

    fun buildPinner(environment: Environment): CertificatePinner {
        val builder = CertificatePinner.Builder()

        when (environment) {
            Environment.PRODUCTION -> {
                builder.add("api.example.com", *PRODUCTION_PINS)
            }
            Environment.STAGING -> {
                builder.add("staging-api.example.com", *STAGING_PINS)
            }
            Environment.DEV -> {
                // DEV environment: no pinning, but still uses strict TLS validation
                // (system trust store is used; no trust-all or hostname bypass)
            }
        }

        return builder.build()
    }
}

// File: TokenRefreshAuthenticator.kt
package com.example.networking

import okhttp3.Authenticator
import okhttp3.Request
import okhttp3.Response
import okhttp3.Route

class TokenRefreshAuthenticator(
    private val tokenProvider: TokenProvider
) : Authenticator {

    companion object {
        private const val MAX_RETRY = 2
    }

    override fun authenticate(route: Route?, response: Response): Request? {
        // Count how many times we've already retried to avoid infinite loops
        val retryCount = responseCount(response)
        if (retryCount >= MAX_RETRY) {
            tokenProvider.clearToken()
            return null
        }

        val newToken = tokenProvider.refreshToken()
        if (newToken.isNullOrBlank()) {
            tokenProvider.clearToken()
            return null
        }

        return response.request.newBuilder()
            .header("Authorization", "Bearer $newToken")
            .build()
    }

    private fun responseCount(response: Response): Int {
        var count = 1
        var priorResponse = response.priorResponse
        while (priorResponse != null) {
            count++
            priorResponse = priorResponse.priorResponse
        }
        return count
    }
}

// File: LoggingInterceptor.kt
package com.example.networking

import okhttp3.logging.HttpLoggingInterceptor

object LoggingInterceptor {
    fun create(environment: Environment): HttpLoggingInterceptor {
        return HttpLoggingInterceptor().apply {
            level = when (environment) {
                Environment.DEV -> HttpLoggingInterceptor.Level.BODY
                Environment.STAGING -> HttpLoggingInterceptor.Level.HEADERS
                Environment.PRODUCTION -> HttpLoggingInterceptor.Level.NONE
            }
            // Redact sensitive headers from logs
            redactHeader("Authorization")
            redactHeader("Cookie")
            redactHeader("Set-Cookie")
        }
    }
}

