package com.example.networking

import com.example.networking.api.UserApiService
import com.google.gson.GsonBuilder
import okhttp3.OkHttpClient
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkModule {

    private const val CONNECT_TIMEOUT_SECONDS = 30L
    private const val READ_TIMEOUT_SECONDS = 30L
    private const val WRITE_TIMEOUT_SECONDS = 30L

    @Volatile
    private var retrofit: Retrofit? = null

    @Volatile
    private var userApiService: UserApiService? = null

    fun initialize(
        environment: Environment,
        tokenProvider: TokenProvider
    ) {
        val okHttpClient = buildOkHttpClient(environment, tokenProvider)
        retrofit = buildRetrofit(environment, okHttpClient)
        userApiService = retrofit!!.create(UserApiService::class.java)
    }

    fun getUserApiService(): UserApiService {
        return userApiService
            ?: throw IllegalStateException("NetworkModule not initialized. Call initialize() first.")
    }

    private fun buildOkHttpClient(
        environment: Environment,
        tokenProvider: TokenProvider
    ): OkHttpClient {
        val builder = OkHttpClient.Builder()
            .connectTimeout(CONNECT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .readTimeout(READ_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .writeTimeout(WRITE_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .addInterceptor(AuthInterceptor(tokenProvider))
            .addInterceptor(LoggingInterceptor.create(environment))
            .authenticator(TokenRefreshAuthenticator(tokenProvider))

        // Apply certificate pinning for staging and production.
        // DEV uses the default system trust store with strict TLS — no trust-all,
        // no hostname verifier bypass.
        val pinner = CertificatePinnerConfig.buildPinner(environment)
        builder.certificatePinner(pinner)

        // Enforce TLS 1.2+ via connection spec
        val strictTlsSpec = okhttp3.ConnectionSpec.Builder(okhttp3.ConnectionSpec.MODERN_TLS)
            .tlsVersions(okhttp3.TlsVersion.TLS_1_2, okhttp3.TlsVersion.TLS_1_3)
            .build()

        builder.connectionSpecs(listOf(strictTlsSpec))

        return builder.build()
    }

    private fun buildRetrofit(environment: Environment, client: OkHttpClient): Retrofit {
        val gson = GsonBuilder()
            .setDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'")
            .create()

        return Retrofit.Builder()
            .baseUrl(environment.baseUrl)
            .client(client)
            .addConverterFactory(GsonConverterFactory.create(gson))
            .build()
    }

    fun reset() {
        retrofit = null
        userApiService = null
    }
}

// File: UserRepository.kt
package com.example.networking.repository

import com.example.networking.api.UserApiService
import com.example.networking.model.ApiResponse
import com.example.networking.model.UserListResponse
import com.example.networking.model.UserProfile
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext

class UserRepository(private val apiService: UserApiService) {

    suspend fun getUsers(page: Int = 1, perPage: Int = 20): ApiResponse<UserListResponse> {
        return safeApiCall { apiService.getUsers(page, perPage) }
    }

    suspend fun getUserById(userId: Long): ApiResponse<UserProfile> {
        return safeApiCall { apiService.getUserById(userId) }
    }

    suspend fun getCurrentUser(): ApiResponse<UserProfile> {
        return safeApiCall { apiService.getCurrentUser() }
    }

    private suspend fun <T> safeApiCall(
        apiCall: suspend () -> retrofit2.Response<T>
    ): ApiResponse<T> {
        return withContext(Dispatchers.IO) {
            try {
                val response = apiCall()
                if (response.isSuccessful) {
                    val body = response.body()
                    if (body != null) {
                        ApiResponse.Success(body)
                    } else {
                        ApiResponse.Error(
                            code = response.code(),
                            message = "Response body is null"
                        )
                    }
                } else {
                    val errorBody = response.errorBody()?.string() ?: "Unknown error"
                    ApiResponse.Error(
                        code = response.code(),
                        message = errorBody
                    )
                }
            } catch (e: java.net.UnknownHostException) {
                ApiResponse.Error(
                    code = -1,
                    message = "No internet connection",
                    throwable = e
                )
            } catch (e: java.net.SocketTimeoutException) {
                ApiResponse.Error(
                    code = -1,
                    message = "Request timed out",
                    throwable = e
                )
            } catch (e: javax.net.ssl.SSLException) {
                ApiResponse.Error(
                    code = -1,
                    message = "Secure connection failed. Please check your network.",
                    throwable = e
                )
            } catch (e: Exception) {
                ApiResponse.Error(
                    code = -1,
                    message = e.localizedMessage ?: "An unexpected error occurred",
                    throwable = e
                )
            }
        }
    }
}

